SELECT /* base.ec.od :: OdOrderItemDiscnt :: selectList */ d.* , ste.site_nm AS site_nm , ord.member_nm AS order_nm , ite.prod_nm AS order_item_nm , cpn.coupon_nm AS coupon_nm , cd_oidt.code_label AS discnt_type_cd_nm FROM od_order_item_discnt d LEFT JOIN sy_site ste ON ste.site_id = d.site_id LEFT JOIN od_order ord ON ord.order_id = d.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = d.order_item_id LEFT JOIN pm_coupon cpn ON cpn.coupon_id = d.coupon_id LEFT JOIN sy_code cd_oidt ON cd_oidt.code_grp = 'ORDER_ITEM_DISCNT_TYPE' AND cd_oidt.code_value = d.discnt_type_cd
ORDER BY d.item_discnt_id ASC ORDER BY d.item_discnt_id DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.od :: OdOrderItemDiscnt :: selectPageList */ d.* , ste.site_nm AS site_nm , ord.member_nm AS order_nm , ite.prod_nm AS order_item_nm , cpn.coupon_nm AS coupon_nm , cd_oidt.code_label AS discnt_type_cd_nm FROM od_order_item_discnt d LEFT JOIN sy_site ste ON ste.site_id = d.site_id LEFT JOIN od_order ord ON ord.order_id = d.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = d.order_item_id LEFT JOIN pm_coupon cpn ON cpn.coupon_id = d.coupon_id LEFT JOIN sy_code cd_oidt ON cd_oidt.code_grp = 'ORDER_ITEM_DISCNT_TYPE' AND cd_oidt.code_value = d.discnt_type_cd
ORDER BY d.item_discnt_id ASC ORDER BY d.item_discnt_id DESC ORDER BY d.reg_date ASC ORDER BY d.reg_date DESC ORDER BY d.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

