site_id = #{siteId}, order_id = #{orderId}, order_item_id = #{orderItemId}, discnt_type_cd = #{discntTypeCd}, coupon_id = #{couponId}, coupon_issue_id = #{couponIssueId}, discnt_rate = #{discntRate}, unit_discnt_amt = #{unitDiscntAmt}, total_discnt_amt = #{totalDiscntAmt}, order_qty = #{orderQty},
